import type { Course, CourseCollection } from '../types/contentful';

const ENVIRONMENT = 'master';
const CONTENT_TYPE = 'course';

function ensureAuth() {
  const space = process.env.NEXT_PUBLIC_CONTENTFUL_SPACE_ID;
  const token = process.env.NEXT_PUBLIC_CONTENTFUL_ACCESS_TOKEN;
  if (!space || !token) {
    throw new Error(
      'Missing Contentful env vars. Set NEXT_PUBLIC_CONTENTFUL_SPACE_ID and NEXT_PUBLIC_CONTENTFUL_ACCESS_TOKEN'
    );
  }
  return { space, token };
}

/**
 * Fetch a single course by slug from Contentful (returns first match or null).
 */
export async function fetchCourseBySlug(slug: string): Promise<Course | null> {
  const { space, token } = ensureAuth();

  const url = `https://cdn.contentful.com/spaces/${space}/environments/${ENVIRONMENT}/entries?content_type=${CONTENT_TYPE}&fields.slug=${encodeURIComponent(
    slug
  )}&limit=1&access_token=${token}`;

  const res = await fetch(url);
  if (!res.ok) {
    throw new Error(`Contentful fetch failed: ${res.status}`);
  }

  const data: CourseCollection = await res.json();
  return Array.isArray(data?.items) && data.items.length > 0 ? data.items[0] : null;
}

/**
 * Fetch all courses.
 */
export async function fetchAllCourses(): Promise<Course[]> {
  const { space, token } = ensureAuth();
  const url = `https://cdn.contentful.com/spaces/${space}/environments/${ENVIRONMENT}/entries?content_type=${CONTENT_TYPE}&access_token=${token}`;
  const res = await fetch(url);
  if (!res.ok) {
    throw new Error(`Contentful fetch failed: ${res.status}`);
  }
  const data: CourseCollection = await res.json();
  return Array.isArray(data?.items) ? data.items : [];
}

export default {
  fetchCourseBySlug,
  fetchAllCourses,
};
